5	describe("MHPCO Claim Office", () => {
6	  // --- Quote: empty / single base items ---
7	  it("should quote 5 G for an empty item list (processing fee only)", () => {
8	    const scenario = {
9	      customer: { yearsWithMHPCO: 0 },
10	      steps: [{ op: "quote", items: [] }],
11	    };
12	    const { results } = runScenario(scenario);
13	    expect(results).toEqual([{ premium: 5 }]);
14	  });
15	  it.todo("should quote 105 G for a single plain sword (100 base + 5 fee) for an existing customer");
