17	  it.todo("should quote 85 G for a single plain staff (80 base + 5 fee)");
18	  it.todo("should quote 45 G for a single plain potion (40 base + 5 fee)");
19	
20	  // --- Quote: components (runes/moonstones) ---
21	  it.todo("should quote 30 G for a single rune (25 base + 5 fee)");
22	  it.todo("should quote 55 G for 2 runes (50 base + 5 fee)");
23	  it.todo("should quote 65 G for 3 runes as a block (60 base + 5 fee)");
24	  it.todo("should quote 105 G for 4 runes (block of 3 + 1 = 60 + 25 + 5 fee)");
25	  it.todo("should quote 180 G for 7 runes (2 blocks of 3 + 1 single = 60 + 60 + 25 + 5 fee)");
26	  it.todo("should quote 80 G for 2 runes + 1 moonstone (no block, different types: 50 + 25 + 5 fee)");
27	  it.todo("should quote 125 G for 3 runes + 3 moonstones (two blocks: 60 + 60 + 5 fee)");
28	
29	  // --- Quote: per-item surcharges ---
30	  it.todo("should add 50% surcharge to a cursed item's base premium");
31	  it.todo("should add 30% surcharge to an item with enchantment level >= 5");
32	  it.todo("should stack cursed and high-enchantment surcharges on the same item");
33	
34	  // --- Quote: policy-wide modifiers ---
35	  it.todo("should add 10% first-insurance surcharge per item for a newcomer customer");
36	  it.todo("should apply 20% loyalty discount when customer has >= 2 years with MHPCO");
37	  it.todo("should apply 15% follow-up contract discount on the second and later contracts");
38	
39	  // --- Quote: rounding and fee ---
40	  it.todo("should round premium up to whole G in MHPCO's favor (e.g. 197.5 -> 198)");
41	  it.todo("should add the 5 G processing fee at the end of premium calculation");
42	
43	  // --- Quote: worked examples from the spec ---
44	  it.todo("should quote 165 G for newcomer cursed steel sword ench 3 (100 + 50 + 10 + 5 fee)");
45	  it.todo("should quote 160 G for 3-year customer's 2nd quote cursed sword ench 7 (100 + 50 + 30 - 20 + 10 - 15 + 5 fee)");
