51	  it.todo("should round payout down to whole G in MHPCO's favor (e.g. 350.5 -> 350)");
52	
53	  // --- Claim: enchantment and material rules ---
54	  it.todo("should reimburse 50% of damage (then deductible) for items with enchantment >= 8");
55	  it.todo("should reimburse damage in full (then deductible) for dragon-material items");
56	  it.todo("should apply the 50% rule (not full reimbursement) when both dragon material and enchantment >= 8 apply");
57	
58	  // --- Claim: worked examples from the spec ---
59	  it.todo("should pay 400 G for dragon sword ench 8 with 1000 G damage (50% wins, then deductible)");
60	  it.todo("should pay 700 G for dragon sword ench 5 with 800 G damage (full reimbursement minus deductible)");
61	  it.todo("should pay 400 G for steel sword ench 9 with 1000 G damage (50% rule, then deductible)");
62	
