64	  it.todo("should pay 1400 G with remainingCap 600 for first 1500 G claim on a sword policy (cap 2000)");
65	  it.todo("should pay 600 G with remainingCap 0 for a second 1500 G claim that hits the cap");
66	
67	  // --- Claim: multiple items of same type ---
68	  it.todo("should treat each damage entry separately (each gets its own deductible) for two damaged swords");
69	
70	  // --- Errors ---
71	  it.todo("should exit non-zero and write to stderr for an unknown item type");
72	  it.todo("should exit non-zero and write to stderr when damage references an unknown item");
73	  it.todo("should exit non-zero and write to stderr for a negative amount");
